import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import Modal from "../components/Modal";
import { filterCoursesByClass } from "../courseReducer";

function Enrollments() {
  const [enrollments, setEnrollments] = useState([]);
  const [files, setFiles] = useState([]);
  const [tests, setTests] = useState([]);
  const [grades, setGrades] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [enrollmentToDelete, setEnrollmentToDelete] = useState(null);
  const [reviewInputs, setReviewInputs] = useState({});
  const [testState, setTestState] = useState({});
  const user = useSelector((state) => state.auth.user);
  const { filteredCourses } = useSelector((state) => state.courses);
  const dispatch = useDispatch();

  useEffect(() => {
    fetch(`http://localhost:3001/enrollments?studentId=${user.id}`)
      .then((res) => res.json())
      .then((data) => setEnrollments(data));
    fetch("http://localhost:3001/files")
      .then((res) => res.json())
      .then((data) => setFiles(data));
    fetch("http://localhost:3001/tests")
      .then((res) => res.json())
      .then((data) => setTests(data));
    fetch(`http://localhost:3001/grades?studentId=${user.id}`)
      .then((res) => res.json())
      .then((data) => setGrades(data));
    if (user.role === "student") {
      dispatch(filterCoursesByClass(user.classId));
    }
  }, [user.id, user.classId, dispatch]);

  async function handleEnroll(e) {
    e.preventDefault();
    if (!selectedCourse) {
      toast.error("Выберите курс.");
      return;
    }

    const courseId = parseInt(selectedCourse);
    const alreadyEnrolled = enrollments.some(
      (enrollment) => parseInt(enrollment.courseId) === courseId
    );
    if (alreadyEnrolled) {
      toast.error("Вы уже записаны на этот курс!");
      return;
    }

    const course = filteredCourses.find((c) => c.id === courseId);
    if (new Date() > new Date(course.deadline)) {
      toast.error("Дедлайн курса истек!");
      return;
    }

    const newEnrollment = { studentId: user.id, courseId };

    try {
      const response = await fetch("http://localhost:3001/enrollments", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newEnrollment),
      });

      if (response.ok) {
        const enrollment = await response.json();
        setEnrollments([...enrollments, enrollment]);
        const courseName = filteredCourses.find((c) => c.id === courseId)?.name;
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Записан на ${courseName}!`,
            createdAt: new Date().toISOString(),
          }),
        });
        toast.success("Успешно записан!");
      } else {
        toast.error("Не удалось записаться");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при записи");
    }
  }

  async function handleUnenroll() {
    try {
      const response = await fetch(
        `http://localhost:3001/enrollments/${enrollmentToDelete}`,
        {
          method: "DELETE",
        }
      );
      if (response.ok) {
        setEnrollments(
          enrollments.filter((e) => e.id !== enrollmentToDelete)
        );
        toast.success("Успешно отписан!");
      } else {
        toast.error("Не удалось отписаться");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при отписке");
    }
    setIsModalOpen(false);
  }

  async function handleReviewSubmit(courseId, courseName, teacherId) {
    const message = reviewInputs[courseId];
    if (!message || message.trim() === "") {
      toast.error("Отзыв или вопрос не может быть пустым!");
      return;
    }

    const newReview = {
      courseId: parseInt(courseId),
      studentId: user.id,
      message: message.trim(),
      createdAt: new Date().toISOString(),
    };

    try {
      const response = await fetch("http://localhost:3001/reviews", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newReview),
      });

      if (response.ok) {
        setReviewInputs((prev) => ({ ...prev, [courseId]: "" }));
        toast.success("Отзыв успешно отправлен!");
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: teacherId,
            message: `Новый отзыв на курс "${courseName}" от студента ${user.name}: ${message}`,
            createdAt: new Date().toISOString(),
          }),
        });
      } else {
        toast.error("Не удалось отправить отзыв");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при отправке отзыва");
    }
  }

  async function handleTestSubmit(testId, courseId, answers) {
    const test = tests.find((t) => t.id === testId);
    let score = 0;
    test.questions.forEach((q, index) => {
      const selectedOptionIndex = q.options.indexOf(answers[index]);
      if (selectedOptionIndex === q.correctAnswerIndex) {
        score += 100 / test.questions.length;
      }
    });

    const newGrade = {
      studentId: user.id,
      courseId,
      testId,
      score: score.toFixed(2),
      createdAt: new Date().toISOString(),
    };

    try {
      const response = await fetch("http://localhost:3001/grades", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newGrade),
      });
      if (response.ok) {
        const savedGrade = await response.json();
        setGrades([...grades, savedGrade]);
        setTestState((prev) => ({
          ...prev,
          [testId]: { ...prev[testId], completed: true },
        }));
        toast.success(`Тест сдан! Оценка: ${score.toFixed(2)}`);
      } else {
        toast.error("Не удалось сохранить результат теста");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при сохранении результата");
    }
  }

  function startTest(testId) {
    const test = tests.find((t) => t.id === testId);
    if (new Date() > new Date(test.deadline)) {
      toast.error("Дедлайн теста истек!");
      return;
    }

    setTestState((prev) => ({
      ...prev,
      [testId]: { timeLeft: test.duration * 60, answers: [], started: true },
    }));

    const timer = setInterval(() => {
      setTestState((prev) => {
        const newTimeLeft = prev[testId].timeLeft - 1;
        if (newTimeLeft <= 0) {
          clearInterval(timer);
          handleTestSubmit(testId, test.courseId, prev[testId].answers);
          return { ...prev, [testId]: { ...prev[testId], completed: true } };
        }
        return { ...prev, [testId]: { ...prev[testId], timeLeft: newTimeLeft } };
      });
    }, 1000);
  }

  function handleReviewInputChange(courseId, value) {
    setReviewInputs((prev) => ({ ...prev, [courseId]: value }));
  }

  function openModal(enrollmentId) {
    setEnrollmentToDelete(enrollmentId);
    setIsModalOpen(true);
  }

  const isImage = (fileName) => /\.(jpg|jpeg|png)$/i.test(fileName);

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Мои записи</h1>
      {user.role === "student" && (
        <div className="card mb-5">
          <div className="card-body">
            <form>
              <div className="mb-3">
                <select
                  value={selectedCourse}
                  onChange={(e) => setSelectedCourse(e.target.value)}
                  className="form-select"
                  aria-label="Выбор курса"
                >
                  <option value="">-- Выберите курс --</option>
                  {filteredCourses.map((course) => (
                    <option key={course.id} value={course.id}>
                      {course.name}
                    </option>
                  ))}
                </select>
              </div>
              <button
                onClick={handleEnroll}
                className="btn btn-primary w-100"
                aria-label="Записаться на курс"
              >
                Записаться
              </button>
            </form>
          </div>
        </div>
      )}
      <h3>Записи</h3>
      <ul className="list-group">
        {enrollments
          .map((enrollment) => {
            const course = filteredCourses.find(
              (c) => c.id === parseInt(enrollment.courseId)
            );
            return course
              ? {
                  ...enrollment,
                  courseName: course.name,
                  teacherId: course.teacherId,
                  courseDeadline: course.deadline,
                }
              : null;
          })
          .filter((enrollment) => enrollment !== null)
          .map((enrollment) => {
            const test = tests.find((t) => t.courseId === enrollment.courseId);
            const courseGrades = grades.filter(
              (g) => g.courseId === enrollment.courseId
            );
            return (
              <li key={enrollment.id} className="list-group-item">
                <div className="d-flex justify-content-between align-items-center">
                  <span>
                    Курс: {enrollment.courseName} (Дедлайн:{" "}
                    {enrollment.courseDeadline})
                  </span>
                  <button
                    onClick={() => openModal(enrollment.id)}
                    className="btn btn-danger btn-sm"
                    aria-label="Отписаться от курса"
                  >
                    Отписаться
                  </button>
                </div>
                <ul className="mt-2">
                  {files
                    .filter((f) => f.courseId === parseInt(enrollment.courseId))
                    .map((f) => (
                      <li key={f.id} className="d-flex align-items-center gap-2">
                        {isImage(f.fileName) ? (
                          <img
                            src={`http://localhost:3002${f.filePath}`}
                            alt={f.fileName}
                            className="img-thumbnail"
                            style={{ width: "100px", height: "100px" }}
                          />
                        ) : (
                          <a
                            href={`http://localhost:3002${f.filePath}`}
                            download
                            className="text-primary"
                          >
                            {f.fileName}
                          </a>
                        )}
                      </li>
                    ))}
                </ul>
                <div className="mt-3">
                  <label
                    htmlFor={`review-${enrollment.courseId}`}
                    className="form-label"
                  >
                    Оставить отзыв или вопрос:
                  </label>
                  <textarea
                    id={`review-${enrollment.courseId}`}
                    className="form-control mb-2"
                    rows="3"
                    value={reviewInputs[enrollment.courseId] || ""}
                    onChange={(e) =>
                      handleReviewInputChange(enrollment.courseId, e.target.value)
                    }
                    placeholder="Напишите ваш отзыв или вопрос..."
                  />
                  <button
                    onClick={() =>
                      handleReviewSubmit(
                        enrollment.courseId,
                        enrollment.courseName,
                        enrollment.teacherId
                      )
                    }
                    className="btn btn-primary btn-sm"
                  >
                    Отправить
                  </button>
                </div>
                {test && !testState[test.id]?.completed && (
                  <div className="mt-3">
                    <h5>
                      Итоговый тест: {test.title} (Дедлайн: {test.deadline})
                    </h5>
                    {new Date() > new Date(test.deadline) ? (
                      <p className="text-danger">Дедлайн теста истек!</p>
                    ) : !testState[test.id]?.started ? (
                      <button
                        onClick={() => startTest(test.id)}
                        className="btn btn-success"
                      >
                        Начать тест
                      </button>
                    ) : (
                      <div>
                        <p>
                          Осталось времени:{" "}
                          {Math.floor(testState[test.id].timeLeft / 60)}:
                          {(testState[test.id].timeLeft % 60)
                            .toString()
                            .padStart(2, "0")}
                        </p>
                        {test.questions.map((q, index) => (
                          <div key={q.id} className="mb-3">
                            <p>{q.text}</p>
                            {q.options.map((option, optIndex) => (
                              <div key={optIndex} className="form-check">
                                <input
                                  type="radio"
                                  name={`question-${q.id}`}
                                  value={option}
                                  className="form-check-input"
                                  checked={testState[test.id]?.answers[index] === option}
                                  onChange={() => {
                                    const newAnswers = [
                                      ...(testState[test.id]?.answers || []),
                                    ];
                                    newAnswers[index] = option;
                                    setTestState((prev) => ({
                                      ...prev,
                                      [test.id]: {
                                        ...prev[test.id],
                                        answers: newAnswers,
                                      },
                                    }));
                                  }}
                                />
                                <label className="form-check-label">
                                  {option}
                                </label>
                              </div>
                            ))}
                          </div>
                        ))}
                        <button
                          onClick={() =>
                            handleTestSubmit(
                              test.id,
                              test.courseId,
                              testState[test.id].answers
                            )
                          }
                          className="btn btn-primary"
                        >
                          Отправить
                        </button>
                      </div>
                    )}
                  </div>
                )}
                {courseGrades.length > 0 && (
                  <div className="mt-3">
                    <h5>Мои оценки</h5>
                    <ul className="list-group">
                      {courseGrades.map((grade) => (
                        <li key={grade.id} className="list-group-item">
                          Тест ID: {grade.testId} | Оценка: {grade.score} | Дата:{" "}
                          {new Date(grade.createdAt).toLocaleDateString()}
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </li>
            );
          })}
      </ul>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={handleUnenroll}
        message="Вы уверены, что хотите отписаться от этого курса?"
      />
    </div>
  );
}

export default Enrollments;
